import{_ as s,o as e,c as t,af as n}from"./chunks/framework.DuHE0XFB.js";const h=JSON.parse('{"title":"iOS 开发 Tips","description":"","frontmatter":{"title":"iOS 开发 Tips","date":"2016-06-09 10:58:59 +0800"},"headers":[],"relativePath":"posts/ios-tips.md","filePath":"posts/ios-tips.md","lastUpdated":1783570921000}'),i={name:"posts/ios-tips.md"};function p(l,a,o,c,d,g){return e(),t("div",null,[...a[0]||(a[0]=[n(`<p>用模拟器调试动画功能时，让动画执行的慢一些</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>模拟器菜单：Debug -&gt; Show Animations</span></span></code></pre></div><p>取两位整数，不够补 0</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>NSLog(@&quot;%@&quot;, [NSString stringWithFormat:@&quot;%02d月&quot;, 3]);</span></span></code></pre></div><p>解码 cms 加密后的授权文件</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>终端：security cms -D -i example.mobileprovision</span></span></code></pre></div><p>查找代码中的中文字符串，做国际化适配时会用到</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Xcode左侧导航处：Find -&gt; Regular Expression，然后输入 @&quot;[^&quot;]*[\\u4E00-\\u9FA5]+[^&quot;\\n]*?&quot;</span></span></code></pre></div><p>忽略第三方 SDK 文档中的警告</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>build settings -&gt;  Other Warning Flags -&gt; -Wno-documentation</span></span></code></pre></div><p>自定义 leftBarButtonItem 后，左滑返回手势失效</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>self.navigationController.interactivePopGestureRecognizer.delegate = self;</span></span></code></pre></div><p>在 xib 中给 UILabel 或 UITextView 设置多行文字</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>输入文字后，用 control + enter 来插入换行符，相当于在代码中添加 \\n</span></span></code></pre></div><p>禁用 UIButton 并且颜色不变灰</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>button.userInteractionEnabled = NO;</span></span></code></pre></div><p>修改约束后，用动画展示效果</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>[UIView animateWithDuration:0.3f animations:^{</span></span>
<span class="line"><span>    [myView layoutIfNeeded];</span></span>
<span class="line"><span>}];</span></span></code></pre></div><p>快速定位视图约束警告</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>po [[UIWindow keyWindow] _autolayoutTrace]</span></span></code></pre></div><p>给 UIView 设置透明度后不影响 subviews</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>superView.backgroundColor = [[UIColor blackColor] colorWithAlphaComponent:0.5];</span></span></code></pre></div><p>隐藏 Grouped TableView 上边多余的间隔</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>self.tableView.tableHeaderView = [[UIView alloc] initWithFrame:CGRectMake(0, 0, 0, CGFLOAT_MIN)];</span></span></code></pre></div><p>编译出 error 后继续编译</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Xcode -&gt; preference -&gt; general -&gt; 勾选 Continue building after errors</span></span></code></pre></div><p>自定义类后，禁止通过 init 方法初始化对象</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>- (instancetype)init UNAVAILABLE_ATTRIBUTE;</span></span>
<span class="line"><span>或</span></span>
<span class="line"><span>- (instancetype)init __attribute__((unavailable(&quot;init 方法不可用，请用 initWithName:&quot;)));</span></span></code></pre></div><p>忽略可以忽略的警告，<a href="http://fuckingclangwarnings.com" target="_blank" rel="noreferrer">更多警告</a></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>#pragma clang diagnostic push</span></span>
<span class="line"><span>#pragma clang diagnostic ignored &quot;-Wdeprecated-declarations&quot;</span></span>
<span class="line"><span></span></span>
<span class="line"><span>#pragma clang diagnostic pop</span></span></code></pre></div>`,30)])])}const u=s(i,[["render",p]]);export{h as __pageData,u as default};
